beforeSaveCustomScript:
ifThen(
    !empty(dateStartDate),
    datadisponibilita = dateStartDate
);
ifThen(
    empty(dateStartDate) && !empty(dateStart),
    datadisponibilita = datetime\format(dateStart, 'Europe/Rome', 'YYYY-MM-DD')
);
ifThen(
    empty(dateStartDate) && empty(dateStart) && !empty(orarioInizio),
    datadisponibilita = datetime\format(orarioInizio, 'Europe/Rome', 'YYYY-MM-DD')
);
